import random
import statistics
import unittest

def generate_unique_random_numbers(start, end, count):
    numbers = set()
    while len(numbers) < count:
        num = random.randint(start, end)
        if num not in numbers:
            numbers.add(num)
    return list(numbers)

def print_generated_numbers(numbers):
    print("generated numbers:")
    for i, num in enumerate(numbers, 1):
        print(f"number {i}: {num}")
    print("\n")

def calculate_mean_and_std_dev(numbers):
    mean = statistics.mean(numbers)
    std_dev = statistics.stdev(numbers)
    return mean, std_dev

def main():
    start_range = 1
    end_range = 100
    number_of_elements = 10
    unique_numbers = generate_unique_random_numbers(start_range, end_range, number_of_elements)
    print_generated_numbers(unique_numbers)
    mean, std_dev = calculate_mean_and_std_dev(unique_numbers)
    print(f"mean: {mean}")
    print(f"standard deviation: {std_dev}")
    print("\n")

if __name__ == "__main__":
    main()
```

